import React from "react";
import { VerticalTimeline, VerticalTimelineElement } from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />,
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
  },
];

const getGradient = (iconType) => {
  if (iconType === "FaBriefcase") return "linear-gradient(to right, #000000, #ffffff)";
  if (iconType === "FaUniversity") return "linear-gradient(to right, #004e92, #000428)";
  if (iconType === "FaCloud") return "linear-gradient(to right, #2193b0, #6dd5ed)";
  return "linear-gradient(to right, #ccc, #eee)";
};

const getIconType = (icon) => {
  if (icon.type === FaBriefcase) return "FaBriefcase";
  if (icon.type === FaUniversity) return "FaUniversity";
  if (icon.type === FaCloud) return "FaCloud";
  return "Other";
};

const sortByDateDesc = (a, b) => {
  const getYear = (dateStr) => parseInt(dateStr.split("-")[0]);
  return getYear(b.date) - getYear(a.date);
};

const Timeline = () => {
  return (
    <VerticalTimeline>
      {experienceData.sort(sortByDateDesc).map((item, index) => {
        const iconType = getIconType(item.icon);
        const gradient = getGradient(iconType);
        const isEducation = iconType === "FaUniversity";

        return (
          <VerticalTimelineElement
            key={index}
            date={item.date}
            iconStyle={{
              background: gradient,
              color: "#fff",
            }}
            icon={item.icon}
            contentStyle={{
              background: "#f0f0f0",
              color: "#000",
              width: "fit-content",
              minWidth: "200px",
              maxWidth: "400px",
              padding: isEducation ? "8px" : "16px",
            }}
            contentArrowStyle={{ borderRight: "7px solid  #f0f0f0" }}
          >
            <h3 className="vertical-timeline-element-title" style={{ fontSize: isEducation ? "1rem" : "1.25rem" }}>
              {item.title}
            </h3>
            <h4 className="vertical-timeline-element-subtitle" style={{ fontSize: isEducation ? "0.9rem" : "1.1rem" }}>
              {item.company}
            </h4>
          </VerticalTimelineElement>
        );
      })}
    </VerticalTimeline>
  );
};

export default Timeline;
